import React, { useState } from 'react';
import { LayoutVisualData } from '../types';

type LayoutType = 'staggered';

interface KeyboardVisualizationProps {
  layoutData: LayoutVisualData;
  highlightedKeys?: string[];
  className?: string;
  onKeyHover?: (key: string) => void;
  showFingerColors?: boolean;
}

interface KeyProps {
  char: string;
  position: string;
  finger?: number;
  isHighlighted?: boolean;
  className?: string;
  onHover?: (key: string) => void;
  showFingerColors?: boolean;
}

const Key: React.FC<KeyProps> = ({ 
  char, 
  position, 
  finger = 0,
  isHighlighted = false, 
  className = "",
  onHover,
  showFingerColors = true
}) => {
  const getFingerColor = (finger: number) => {
    const colors = [
      'bg-red-200 dark:bg-red-800 hover:bg-red-300 dark:hover:bg-red-700', // LP (0)
      'bg-orange-200 dark:bg-orange-800 hover:bg-orange-300 dark:hover:bg-orange-700', // LR (1)
      'bg-yellow-200 dark:bg-yellow-800 hover:bg-yellow-300 dark:hover:bg-yellow-700', // LM (2)
      'bg-green-200 dark:bg-green-800 hover:bg-green-300 dark:hover:bg-green-700', // LI (3)
      'bg-blue-200 dark:bg-blue-800 hover:bg-blue-300 dark:hover:bg-blue-700', // LT (4)
      'bg-blue-300 dark:bg-blue-700 hover:bg-blue-400 dark:hover:bg-blue-600', // RT (5)
      'bg-green-300 dark:bg-green-700 hover:bg-green-400 dark:hover:bg-green-600', // RI (6)
      'bg-yellow-300 dark:bg-yellow-700 hover:bg-yellow-400 dark:hover:bg-yellow-600', // RM (7)
      'bg-orange-300 dark:bg-orange-700 hover:bg-orange-400 dark:hover:bg-orange-600', // RR (8)
      'bg-red-300 dark:bg-red-700 hover:bg-red-400 dark:hover:bg-red-600', // RP (9)
    ];
    return colors[finger] || 'bg-gray-300 dark:bg-gray-700 hover:bg-gray-400 dark:hover:bg-gray-600';
  };

  const getKeySize = (pos: string) => {
    // HHKB-specific key sizes
    if (pos === 'tab') return 'w-16';
    if (pos === 'ctrl') return 'w-18';
    if (pos === 'shift') return 'w-24';
    if (pos === 'shift-r') return 'w-20';
    if (pos === 'enter') return 'w-18';
    if (pos === 'space') return 'w-32';
    if (pos === 'backspace') return 'w-16';
    if (pos === 'meta-l' || pos === 'meta-r' || pos === 'alt-l' || pos === 'alt-r' || pos === 'fn') return 'w-12';
    return 'w-12';
  };

  return (
    <div
      className={`
        flex 
        items-center 
        justify-center 
        font-mono 
        text-sm 
        font-semibold
        text-gray-800 
        dark:text-gray-200
        cursor-pointer
        transition-all
        duration-150
        rounded-lg 
        border-2 
        border-gray-300
        dark:border-gray-600
        ${showFingerColors ? getFingerColor(finger) : 'bg-gray-200 dark:bg-gray-700 hover:bg-gray-300 dark:hover:bg-gray-600'}
        ${isHighlighted ? 'ring-4 ring-purple-500 ring-opacity-50 scale-105' : ''}
        ${className}
      `}
      onMouseEnter={() => onHover?.(char)}
      title={`${char.toUpperCase()} - Finger ${finger + 1}`}
    >
      {char}
    </div>
  );
};

// Define finger assignments for keys (0-9 mapping to LP, LR, LM, LI, LT, RT, RI, RM, RR, RP)
const getFingerForKey = (key: string): number => {
  const fingerMap: { [key: string]: number } = {
    // Number row
    '`': 0, '1': 0, '2': 1, '3': 2, '4': 3, '5': 3, '6': 6, '7': 6, '8': 7, '9': 8, '0': 9, '-': 9, '=': 9,
    // Top row  
    'q': 0, 'w': 1, 'e': 2, 'r': 3, 't': 3, 'y': 6, 'u': 6, 'i': 7, 'o': 8, 'p': 9, '[': 9, ']': 9,
    // Home row
    'a': 0, 's': 1, 'd': 2, 'f': 3, 'g': 3, 'h': 6, 'j': 6, 'k': 7, 'l': 8, ';': 9, "'": 9,
    // Bottom row
    'z': 0, 'x': 1, 'c': 2, 'v': 3, 'b': 3, 'n': 6, 'm': 6, ',': 7, '.': 8, '/': 9
  };
  return fingerMap[key.toLowerCase()] ?? 4;
};

const KeyboardVisualization: React.FC<KeyboardVisualizationProps> = ({
  layoutData,
  highlightedKeys = [],
  className = "",
  onKeyHover,
  showFingerColors = true
}) => {
  const [layoutType, setLayoutType] = useState<LayoutType>('staggered');
  const keys = layoutData.keys || {};

  const renderStaggeredLayout = () => (
    <div className="bg-gray-200 dark:bg-gray-700 p-6 rounded-xl shadow-lg max-w-4xl mx-auto">
      <div className="bg-gray-800 dark:bg-gray-900 p-4 rounded-lg shadow-inner">
        <div className="flex flex-col gap-1">
          {/* Row 1: Esc + Numbers - 15 keys total */}
          <div className="flex gap-1">
            <Key char="esc" position="esc" finger={0} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="1" position="1" finger={0} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="2" position="2" finger={1} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="3" position="3" finger={2} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="4" position="4" finger={3} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="5" position="5" finger={3} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="6" position="6" finger={6} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="7" position="7" finger={6} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="8" position="8" finger={7} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="9" position="9" finger={8} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="0" position="0" finger={9} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="-" position="-" finger={9} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="=" position="=" finger={9} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="\\" position="\\" finger={9} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="`" position="`" finger={9} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
          </div>
          
          {/* Row 2: Tab + QWERTY - 14 keys total, add 1 spacer */}
          <div className="flex gap-1">
            <Key char="⇥" position="tab" finger={0} className="w-16 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.q || 'q'} position="q" finger={getFingerForKey(keys.q || 'q')} isHighlighted={highlightedKeys.includes('q')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.w || 'w'} position="w" finger={getFingerForKey(keys.w || 'w')} isHighlighted={highlightedKeys.includes('w')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.e || 'e'} position="e" finger={getFingerForKey(keys.e || 'e')} isHighlighted={highlightedKeys.includes('e')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.r || 'r'} position="r" finger={getFingerForKey(keys.r || 'r')} isHighlighted={highlightedKeys.includes('r')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.t || 't'} position="t" finger={getFingerForKey(keys.t || 't')} isHighlighted={highlightedKeys.includes('t')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.y || 'y'} position="y" finger={getFingerForKey(keys.y || 'y')} isHighlighted={highlightedKeys.includes('y')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.u || 'u'} position="u" finger={getFingerForKey(keys.u || 'u')} isHighlighted={highlightedKeys.includes('u')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.i || 'i'} position="i" finger={getFingerForKey(keys.i || 'i')} isHighlighted={highlightedKeys.includes('i')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.o || 'o'} position="o" finger={getFingerForKey(keys.o || 'o')} isHighlighted={highlightedKeys.includes('o')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.p || 'p'} position="p" finger={getFingerForKey(keys.p || 'p')} isHighlighted={highlightedKeys.includes('p')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="[" position="[" finger={9} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="]" position="]" finger={9} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="⌫" position="backspace" finger={9} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <div className="w-12 h-12"></div>
          </div>
          
          {/* Row 3: Control + Home row - 13 keys total, add 2 spacers */}
          <div className="flex gap-1">
            <Key char="ctrl" position="ctrl" finger={0} className="w-20 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.a || 'a'} position="a" finger={getFingerForKey(keys.a || 'a')} isHighlighted={highlightedKeys.includes('a')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.s || 's'} position="s" finger={getFingerForKey(keys.s || 's')} isHighlighted={highlightedKeys.includes('s')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.d || 'd'} position="d" finger={getFingerForKey(keys.d || 'd')} isHighlighted={highlightedKeys.includes('d')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.f || 'f'} position="f" finger={getFingerForKey(keys.f || 'f')} isHighlighted={highlightedKeys.includes('f')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.g || 'g'} position="g" finger={getFingerForKey(keys.g || 'g')} isHighlighted={highlightedKeys.includes('g')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.h || 'h'} position="h" finger={getFingerForKey(keys.h || 'h')} isHighlighted={highlightedKeys.includes('h')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.j || 'j'} position="j" finger={getFingerForKey(keys.j || 'j')} isHighlighted={highlightedKeys.includes('j')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.k || 'k'} position="k" finger={getFingerForKey(keys.k || 'k')} isHighlighted={highlightedKeys.includes('k')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.l || 'l'} position="l" finger={getFingerForKey(keys.l || 'l')} isHighlighted={highlightedKeys.includes('l')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys[';'] || ';'} position=";" finger={getFingerForKey(keys[';'] || ';')} isHighlighted={highlightedKeys.includes(';')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys["'"] || "'"} position="'" finger={9} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="↵" position="enter" finger={9} className="w-16 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <div className="w-8 h-12"></div>
          </div>
          
          {/* Row 4: Shift + bottom letters - 13 keys total, add 2 spacers */}
          <div className="flex gap-1">
            <Key char="⇧" position="shift" finger={0} className="w-24 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.z || 'z'} position="z" finger={getFingerForKey(keys.z || 'z')} isHighlighted={highlightedKeys.includes('z')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.x || 'x'} position="x" finger={getFingerForKey(keys.x || 'x')} isHighlighted={highlightedKeys.includes('x')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.c || 'c'} position="c" finger={getFingerForKey(keys.c || 'c')} isHighlighted={highlightedKeys.includes('c')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.v || 'v'} position="v" finger={getFingerForKey(keys.v || 'v')} isHighlighted={highlightedKeys.includes('v')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.b || 'b'} position="b" finger={getFingerForKey(keys.b || 'b')} isHighlighted={highlightedKeys.includes('b')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.n || 'n'} position="n" finger={getFingerForKey(keys.n || 'n')} isHighlighted={highlightedKeys.includes('n')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys.m || 'm'} position="m" finger={getFingerForKey(keys.m || 'm')} isHighlighted={highlightedKeys.includes('m')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys[','] || ','} position="," finger={getFingerForKey(keys[','] || ',')} isHighlighted={highlightedKeys.includes(',')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys['.'] || '.'} position="." finger={getFingerForKey(keys['.'] || '.')} isHighlighted={highlightedKeys.includes('.')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char={keys['/'] || '/'} position="/" finger={getFingerForKey(keys['/'] || '/')} isHighlighted={highlightedKeys.includes('/')} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="⇧" position="shift-r" finger={9} className="w-16 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="fn" position="fn" finger={9} className="w-12 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <div className="w-8 h-12"></div>
          </div>
          
          {/* Row 5: Bottom modifier row */}
          <div className="flex gap-1 justify-center">
            <Key char="◇" position="meta-l" finger={4} className="w-14 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="alt" position="alt-l" finger={4} className="w-14 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="space" position="space" finger={5} className="w-32 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="alt" position="alt-r" finger={5} className="w-14 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
            <Key char="◇" position="meta-r" finger={5} className="w-14 h-12" onHover={onKeyHover} showFingerColors={showFingerColors} />
          </div>
        </div>
      </div>
    </div>
  );



  const getCurrentLayout = () => {
    return renderStaggeredLayout();
  };

  return (
    <div className={`bg-white dark:bg-gray-900 rounded-xl p-6 ${className}`}>

      {/* Keyboard Layout */}
      <div className="keyboard-container flex justify-center">
        {getCurrentLayout()}
      </div>
      
      {/* Legend */}
      {showFingerColors && (
        <div className="mt-6 flex flex-wrap gap-2 justify-center text-xs">
          <div className="flex items-center gap-1">
            <div className="w-3 h-3 rounded bg-red-200 dark:bg-red-800 border"></div>
            <span>LP</span>
          </div>
          <div className="flex items-center gap-1">
            <div className="w-3 h-3 rounded bg-orange-200 dark:bg-orange-800 border"></div>
            <span>LR</span>
          </div>
          <div className="flex items-center gap-1">
            <div className="w-3 h-3 rounded bg-yellow-200 dark:bg-yellow-800 border"></div>
            <span>LM</span>
          </div>
          <div className="flex items-center gap-1">
            <div className="w-3 h-3 rounded bg-green-200 dark:bg-green-800 border"></div>
            <span>LI</span>
          </div>
          <div className="flex items-center gap-1">
            <div className="w-3 h-3 rounded bg-blue-200 dark:bg-blue-800 border"></div>
            <span>Thumb</span>
          </div>
          <div className="flex items-center gap-1">
            <div className="w-3 h-3 rounded bg-green-300 dark:bg-green-700 border"></div>
            <span>RI</span>
          </div>
          <div className="flex items-center gap-1">
            <div className="w-3 h-3 rounded bg-yellow-300 dark:bg-yellow-700 border"></div>
            <span>RM</span>
          </div>
          <div className="flex items-center gap-1">
            <div className="w-3 h-3 rounded bg-orange-300 dark:bg-orange-700 border"></div>
            <span>RR</span>
          </div>
          <div className="flex items-center gap-1">
            <div className="w-3 h-3 rounded bg-red-300 dark:bg-red-700 border"></div>
            <span>RP</span>
          </div>
        </div>
      )}
    </div>
  );
};

export default KeyboardVisualization;
